168	// drainServiceEvents reads service events and returns the final-event payload,
169	// the routing decision (when present in the routing_decision start event), and
170	// any canonical progress payloads emitted by the service.
171	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
172		return drainServiceEventsWithWriter(events, nil)
173	}
174	
175	func drainServiceEventsWithWriter(events <-chan agentlib.ServiceEvent, w io.Writer) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
176		return drainServiceEventsWithRenderer(events, w, NewWorkLogRenderer(WorkLogRendererOptions{WorkPhase: "do"}))
177	}
178	
179	func drainServiceEventsWithRenderer(events <-chan agentlib.ServiceEvent, w io.Writer, renderer WorkLogRenderer) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
180		var final *agentlib.ServiceFinalData
181		var routing *agentlib.ServiceRoutingDecisionData
182		var progress []agentlib.ServiceProgressData
183	
184		for ev := range events {
185			decoded, err := agentlib.DecodeServiceEvent(ev)
186			if err != nil {
187				continue
188			}
189			switch {
190			case decoded.RoutingDecision != nil:
191				routing = decoded.RoutingDecision
192				if w != nil {
193					if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
194						_, _ = fmt.Fprint(w, line)
195					}
196				}
197			case decoded.Progress != nil:
198				progress = append(progress, *decoded.Progress)
199				if w != nil {
200					_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
201				}
202			case decoded.Final != nil:
203				final = decoded.Final
204			}
205		}
206		return final, routing, progress
207	}
208	
209	func selectedRoutingCandidateMetrics(routing *agentlib.ServiceRoutingDecisionData) (int, float64, float64, string) {
210		if routing == nil {
211			return 0, 0, 0, ""
212		}
213		for _, candidate := range routing.Candidates {
214			if candidate.Eligible && candidate.Model == routing.Model {
215				return candidate.Components.Power, candidate.Components.SpeedTPS, candidate.CostUSDPer1kTokens, candidate.CostSource
216			}
217		}
218		return 0, 0, 0, ""
219	}
