19	// serviceRunFactory, when non-nil, overrides NewServiceFromWorkDir inside
20	// RunWithConfigViaService. CLI-level integration tests inject a stub to
21	// observe ServiceExecuteRequest fields without a real agent server.
22	var serviceRunFactory func(workDir string) (agentlib.FizeauService, error)
23	
24	// SetServiceRunFactory installs a service factory for RunWithConfigViaService.
25	// Pass nil to restore production behavior. Exported for cmd/ integration tests.
26	//
27	// Production reachability: invoked from init() with nil so the symbol is
28	// reachable from main() under deadcode RTA. Real overrides come from cmd/
29	// integration tests at test-setup time.
30	func SetServiceRunFactory(f func(workDir string) (agentlib.FizeauService, error)) {
31		serviceRunFactory = f
32	}
33	
34	func init() {
35		// Reach SetServiceRunFactory from main() so it survives deadcode RTA.
36		// The nil reset is a no-op: production never sets the factory.
37		SetServiceRunFactory(nil)
38	}
