335	func metadataWithEnv(metadata, env map[string]string) map[string]string {
336		if len(metadata) == 0 && len(env) == 0 {
337			return nil
338		}
339		out := make(map[string]string, len(metadata)+len(env))
340		for k, v := range metadata {
341			out[k] = v
342		}
343		for k, v := range env {
344			out[k] = v
345		}
346		return out
347	}
348	
349	func normalizeServiceFinalExitCode(result *Result) {
350		if result == nil {
351			return
352		}
353		if result.ExitCode == 0 && strings.TrimSpace(result.Error) != "" {
354			result.ExitCode = 1
355		}
356	}
