415	// TestProviderConnectivityViaService runs a HealthCheck against the named
416	// harness and translates the result into a ProviderStatus. It is the
417	// production replacement for Runner.TestProviderConnectivity.
418	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
419		status := ProviderStatus{Reachable: false}
420		if ctx == nil {
421			ctx = context.Background()
422		}
423		if harnessName == "virtual" || harnessName == "agent" {
424			status.Reachable = true
425			status.CreditsOK = true
426			return status
427		}
428		svc, err := NewServiceFromWorkDir(workDir)
429		if err != nil {
430			status.Error = err.Error()
431			return status
432		}
433		if timeout > 0 {
434			var cancel context.CancelFunc
435			ctx, cancel = context.WithTimeout(ctx, timeout)
436			defer cancel()
437		}
438		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
439			errStr := strings.ToLower(err.Error())
440			status.Error = err.Error()
441			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
442				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
443				status.CreditsOK = false
444			}
445			return status
446		}
447		status.Reachable = true
448		status.CreditsOK = true
449		return status
450	}
451	
452	// ValidateForExecuteLoopViaService is the production replacement for
453	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
454	// will pick at claim time). When harness is specified it confirms the harness
455	// exists in the service registry and (when model is set) attempts a
456	// ResolveRoute pre-flight.
457	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
458		if harnessName == "" {
459			return nil
460		}
461		if ctx == nil {
462			ctx = context.Background()
463		}
464		svc, err := NewServiceFromWorkDir(workDir)
465		if err != nil {
466			return fmt.Errorf("agent: build service: %w", err)
467		}
468		infos, err := svc.ListHarnesses(ctx)
469		if err != nil {
470			return fmt.Errorf("agent: list harnesses: %w", err)
471		}
472		found := false
473		for _, info := range infos {
474			if info.Name == harnessName {
475				found = true
476				if !info.Available {
477					return fmt.Errorf("agent: harness %s not available", harnessName)
478				}
479				break
480			}
481		}
482		if !found {
483			return fmt.Errorf("agent: unknown harness: %s", harnessName)
484		}
485	
486		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
487		// model is provided and provider/model-ref are not set.
488		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
489			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
490				Model:    model,
491				Harness:  harnessName,
492				ModelRef: modelRef,
493				Provider: provider,
494			}); err != nil {
495				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
496			}
497		}
498		return nil
499	}
500	
501	// ValidateEffortForRunViaService rejects effort requests that no currently
502	// available harness can satisfy. `ddx agent run` passes effort through to the
503	// service rather than resolving a route locally, but the command still needs a
504	// fast failure for obviously impossible combinations so operators get a useful
505	// error instead of a silent success path.
506	func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
507		if effort == "" {
508			return nil
509		}
510		if ctx == nil {
511			ctx = context.Background()
512		}
513		svc, err := NewServiceFromWorkDir(workDir)
514		if err != nil {
515			return fmt.Errorf("agent: build service: %w", err)
516		}
517		infos, err := svc.ListHarnesses(ctx)
518		if err != nil {
519			return fmt.Errorf("agent: list harnesses: %w", err)
520		}
521		registry := newHarnessRegistry()
522		for _, info := range infos {
523			if !info.Available {
524				continue
525			}
526			if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
527				return nil
528			}
529		}
530		if profile == "" {
531			return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
532		}
533		return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
534	}
