10	const (
11		routingOutcomeFileName = "routing-outcomes.jsonl"
12		burnSummaryFileName    = "burn-summaries.jsonl"
13	)
14	
15	// RoutingMetricsStore persists minimal routing outcome and quota snapshot data.
16	type RoutingMetricsStore struct {
17		Dir string
18	}
19	
20	// NewRoutingMetricsStore creates a store rooted at dir.
21	func NewRoutingMetricsStore(dir string) *RoutingMetricsStore {
22		return &RoutingMetricsStore{Dir: dir}
23	}
24	
25	func (s *RoutingMetricsStore) outcomeFile() string {
26		return filepath.Join(s.Dir, routingOutcomeFileName)
27	}
28	
29	func (s *RoutingMetricsStore) burnFile() string {
30		return filepath.Join(s.Dir, burnSummaryFileName)
31	}
32	
33	// AppendOutcome writes one routing outcome record.
34	func (s *RoutingMetricsStore) AppendOutcome(outcome RoutingOutcome) error {
35		return appendJSONLRecord(s.outcomeFile(), outcome)
36	}
37	
38	// ReadOutcomes loads all recorded routing outcomes.
39	func (s *RoutingMetricsStore) ReadOutcomes() ([]RoutingOutcome, error) {
40		return ReadAllJSONL[RoutingOutcome](s.outcomeFile())
41	}
42	
43	// ReadBurnSummaries loads stored burn summaries.
44	func (s *RoutingMetricsStore) ReadBurnSummaries() ([]BurnSummary, error) {
45		return ReadAllJSONL[BurnSummary](s.burnFile())
46	}
47	
48	func appendJSONLRecord(path string, v any) error {
49		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
50			return err
51		}
52		data, err := json.Marshal(v)
53		if err != nil {
54			return err
55		}
56		f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
57		if err != nil {
58			return err
59		}
60		defer f.Close()
61		if _, err := f.Write(append(data, '\n')); err != nil {
62			return err
63		}
64		return nil
65	}
66	
67	func (r *Runner) recordRoutingOutcome(result *Result, elapsed time.Duration, opts RunArgs) {
68		if r == nil || result == nil || r.Config.SessionLogDir == "" {
69			return
70		}
71	
72		harness, _ := r.registry.Get(result.Harness)
73		canonicalTarget := result.Model
74		if canonicalTarget == "" {
75			canonicalTarget = opts.Model
76		}
77		if canonicalTarget == "" && harness.DefaultModel != "" {
78			canonicalTarget = harness.DefaultModel
79		}
80		if canonicalTarget == "" {
81			canonicalTarget = result.Harness
82		}
83	
84		outcome := RoutingOutcome{
85			Harness:         result.Harness,
86			Surface:         harness.Surface,
87			CanonicalTarget: canonicalTarget,
88			Model:           result.Model,
89			ObservedAt:      time.Now().UTC(),
90			Success:         result.ExitCode == 0 && result.Error == "",
91			LatencyMS:       int(elapsed.Milliseconds()),
92			InputTokens:     result.InputTokens,
93			OutputTokens:    result.OutputTokens,
94			CostUSD:         result.CostUSD,
95			NativeSessionID: result.AgentSessionID,
96		}
97	
98		if opts.Correlation != nil {
99			outcome.TraceID = opts.Correlation["trace_id"]
100			outcome.SpanID = opts.Correlation["span_id"]
101			if outcome.NativeSessionID == "" {
102				outcome.NativeSessionID = opts.Correlation["native_session_id"]
103			}
104			if outcome.NativeLogRef == "" {
105				outcome.NativeLogRef = opts.Correlation["native_log_ref"]
106			}
107		}
108	
109		_ = NewRoutingMetricsStore(r.Config.SessionLogDir).AppendOutcome(outcome)
110	}
