179	func drainServiceEventsWithRenderer(events <-chan agentlib.ServiceEvent, w io.Writer, renderer WorkLogRenderer) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
180		var final *agentlib.ServiceFinalData
181		var routing *agentlib.ServiceRoutingDecisionData
182		var progress []agentlib.ServiceProgressData
183	
184		for ev := range events {
185			decoded, err := agentlib.DecodeServiceEvent(ev)
186			if err != nil {
187				continue
188			}
189			switch {
190			case decoded.RoutingDecision != nil:
191				routing = decoded.RoutingDecision
192				if w != nil {
193					if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
194						_, _ = fmt.Fprint(w, line)
195					}
196				}
197			case decoded.Progress != nil:
198				progress = append(progress, *decoded.Progress)
199				if w != nil {
200					_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
201				}
202			case decoded.Final != nil:
203				final = decoded.Final
204			}
205		}
206		return final, routing, progress
207	}
